={{ (function() {
  const opportunities = $('Fetch Follow Up 21 Opportunities').all();
  if (!opportunities.length) return "SELECT Id, WhatId, Subject, ActivityDate, CreatedDate FROM Task WHERE Id = null LIMIT 1";
  const esc = (s) => String(s).replace(/'/g, "\\'");
  const subjects = [
    'Qualified Follow Up - Email #1',
    'Qualified Follow Up - Call #1',
    'Qualified Follow Up - Email #2',
    'Qualified Follow Up - Call #2',
    'Qualified Follow Up - Proposal Readiness Review',
    'Qualified Follow Up - Email #3',
    'Qualified Follow Up - Call #3',
    'Qualified Follow Up - Schedule Meeting',
    'Qualified Follow Up - Email #4',
    'Qualified Follow Up - Call #4',
    'Qualified Follow Up - Status Review'
  ];
  const subjectList = subjects.map((s) => "'" + esc(s) + "'").join(', ');
  const opportunityIds = opportunities.map((o) => "'" + esc(o.json.Id) + "'").join(', ');
  return "SELECT Id, WhatId, Subject, ActivityDate, CreatedDate FROM Task WHERE WhatId IN (" + opportunityIds + ") AND Subject IN (" + subjectList + ") LIMIT 1000";
})() }}

