const STEPS = [
  {
    key: 'Day_0',
    offsetDays: 0,
    subject: 'Qualified Follow Up - Email #1',
    action: 'Send Follow Up email #1 and review missing proposal inputs.',
    guidelines: 'Thank the prospect for the conversation, confirm the next step, and list the information still needed to prepare an accurate proposal.'
  },
  {
    key: 'Day_1',
    offsetDays: 1,
    subject: 'Qualified Follow Up - Call #1',
    action: 'Complete follow-up call #1.',
    guidelines: 'Confirm priorities, the decision process, PMS, estimated units, insurance or program questions if applicable, and the best timing for the next meeting.'
  },
  {
    key: 'Day_3',
    offsetDays: 3,
    subject: 'Qualified Follow Up - Email #2',
    action: 'Send information request or recap email #2.',
    guidelines: 'Summarize what is still needed, including portfolio details, PMS, timeline, stakeholders, insurance or policy details when relevant, pricing assumptions, and technical questions.'
  },
  {
    key: 'Day_5',
    offsetDays: 5,
    subject: 'Qualified Follow Up - Call #2',
    action: 'Complete follow-up call #2.',
    guidelines: 'Keep momentum, answer questions, and schedule another meeting if the proposal inputs are incomplete.'
  },
  {
    key: 'Day_7',
    offsetDays: 7,
    subject: 'Qualified Follow Up - Proposal Readiness Review',
    action: 'Complete an internal proposal readiness review.',
    guidelines: 'Review whether enough information exists to create the proposal. If not, document the blockers and the next information needed.'
  },
  {
    key: 'Day_10',
    offsetDays: 10,
    subject: 'Qualified Follow Up - Email #3',
    action: 'Send follow-up email #3 with the specific missing items or a next-meeting call to action.',
    guidelines: 'Keep the email concise and practical. Ask for the missing details or propose a short meeting with Example User or Io to resolve open questions.'
  },
  {
    key: 'Day_12',
    offsetDays: 12,
    subject: 'Qualified Follow Up - Call #3',
    action: 'Complete follow-up call #3.',
    guidelines: 'Resolve open items, confirm whether insurance or program review is still pending, and confirm who else needs to be involved.'
  },
  {
    key: 'Day_14',
    offsetDays: 14,
    subject: 'Qualified Follow Up - Schedule Meeting',
    action: 'Schedule or confirm a follow-up meeting if proposal inputs are still incomplete.',
    guidelines: 'Use this task when there are multiple open details, insurance policy or program reviews, technical questions, or stakeholder alignment still needed.'
  },
  {
    key: 'Day_16',
    offsetDays: 16,
    subject: 'Qualified Follow Up - Email #4',
    action: 'Send follow-up email #4 and complete the proposal readiness check.',
    guidelines: 'Ask whether the prospect is ready for proposal creation or what still needs to be reviewed before moving forward.'
  },
  {
    key: 'Day_18',
    offsetDays: 18,
    subject: 'Qualified Follow Up - Call #4',
    action: 'Complete follow-up call #4.',
    guidelines: 'Make the final call attempt within the 21-day cycle to confirm proposal readiness, the next meeting, or the remaining blockers.'
  },
  {
    key: 'Day_21',
    offsetDays: 21,
    subject: 'Qualified Follow Up - Status Review',
    action: 'Review the Opportunity status and choose the next step.',
    guidelines: 'Move the Opportunity to Proposal if the proposal has been sent. Restart another 21-day Follow Up Sequence if active review continues, set a dated Next Follow-Up Date, or move the Opportunity to Closed Lost if no viable path remains.'
  }
];

const DAY0_SUBJECT = 'Qualified Follow Up - Email #1';
const tz = 'America/Los_Angeles';
const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });

function addDays(dateStr, days) {
  const [y, m, d] = dateStr.split('-').map(Number);
  const dt = new Date(Date.UTC(y, m - 1, d + days));
  return dt.toISOString().slice(0, 10);
}

function toW11DateTime(dateStr) {
  const [y, m, d] = dateStr.split('-').map(Number);
  return new Date(Date.UTC(y, m - 1, d, 20, 0, 0)).toISOString();
}

function buildStepResult(opportunity, step, anchorDate) {
  const opportunityId = String(opportunity.Id || '');
  const stepIndex = STEPS.findIndex((s) => s.key === step.key);
  const isFinalStep = step.key === 'Day_21';
  const effectiveAnchor = anchorDate || todayStr;
  const isDay0Bootstrap = step.offsetDays === 0 && !anchorDate;
  const rawDueDateStr = isDay0Bootstrap ? todayStr : addDays(effectiveAnchor, step.offsetDays);
  const needsW11Gate = !isDay0Bootstrap;
  let nextFollowUpRawDateStr = '';
  if (!isFinalStep) {
    const nextStep = STEPS[stepIndex + 1];
    if (nextStep) {
      nextFollowUpRawDateStr = addDays(effectiveAnchor, nextStep.offsetDays);
    }
  }
  return {
    json: {
      opportunityId,
      sequenceKey: opportunityId + '_FollowUp21',
      opportunityName: String(opportunity.Name || ''),
      opportunityOwnerId: String(opportunity.OwnerId || ''),
      anchorDate: effectiveAnchor,
      stepKey: step.key,
      stepIndex,
      taskSubject: step.subject,
      taskAction: step.action,
      taskGuidelines: step.guidelines,
      isFinalStep,
      needsW11Gate,
      rawDueDateStr,
      w11DueDateTime: toW11DateTime(rawDueDateStr),
      nextFollowUpRawDateStr,
      w11NextDateTime: nextFollowUpRawDateStr ? toW11DateTime(nextFollowUpRawDateStr) : '',
      w11Timezone: tz,
      todayStr
    }
  };
}

const tasksByOpportunity = {};
const day0AnchorByOpportunity = {};

for (const t of $('Fetch Sequence Tasks - Opportunities').all()) {
  const what = String(t.json.WhatId || '');
  const subj = String(t.json.Subject || '');
  if (!what || !subj) continue;
  if (!tasksByOpportunity[what]) tasksByOpportunity[what] = new Set();
  tasksByOpportunity[what].add(subj);

  if (subj === DAY0_SUBJECT) {
    const activityDate = String(t.json.ActivityDate || '').slice(0, 10);
    const createdDate = String(t.json.CreatedDate || '').slice(0, 10);
    const anchor = activityDate || createdDate;
    if (anchor && (!day0AnchorByOpportunity[what] || anchor < day0AnchorByOpportunity[what])) {
      day0AnchorByOpportunity[what] = anchor;
    }
  }
}

const results = [];

for (const item of $('Fetch Follow Up 21 Opportunities').all()) {
  const opportunity = item.json;
  const opportunityId = String(opportunity.Id || '');
  if (!opportunityId) continue;

  // Only Opportunities whose Engagement Status picklist is currently
  // "Follow Up (21)" remain eligible for this sequence.
  // Closed Opportunities are excluded by the SOQL filter.
  const existingSubjects = tasksByOpportunity[opportunityId] || new Set();
  const anchorDate = day0AnchorByOpportunity[opportunityId] || null;
  const stepsToCreate = [];

  if (!anchorDate) {
    if (!existingSubjects.has(DAY0_SUBJECT)) {
      stepsToCreate.push(STEPS[0]);
    }
  } else {
    for (let i = 1; i < STEPS.length; i++) {
      const step = STEPS[i];
      if (existingSubjects.has(step.subject)) continue;
      stepsToCreate.push(step);
      break;
    }
  }

  for (const step of stepsToCreate) {
    results.push(buildStepResult(opportunity, step, anchorDate));
  }
}

return results;

const preItems = $('Determine Follow Up 21 Sequence Step').all();
const results = [];

for (const w11Item of $input.all()) {
  const pi = w11Item.pairedItem?.item;
  if (pi === undefined || pi === null) continue;

  const ctx = preItems[pi]?.json;
  if (!ctx || !ctx.opportunityId) continue;

  if (ctx.needsW11Gate !== true) {
    results.push({ json: { ...ctx, adjustedDueDateStr: ctx.rawDueDateStr } });
    continue;
  }

  const w11 = w11Item.json || {};
  let adjustedDueDateStr = null;
  if (w11.isBusinessDay === true) {
    adjustedDueDateStr = String(w11.localDate || w11.nextBusinessDay || '').substring(0, 10);
  } else {
    adjustedDueDateStr = String(w11.nextBusinessDay || '').substring(0, 10);
  }
  if (!adjustedDueDateStr || adjustedDueDateStr.length < 8) continue;
  if (adjustedDueDateStr > ctx.todayStr) continue;

  results.push({ json: { ...ctx, adjustedDueDateStr } });
}

return results;

